package agent

import (
	"context"
	"errors"
	"fmt"
	"sort"
	"time"

	"github.com/go-logr/logr"
	pb "github.com/nginx/agent/v3/api/grpc/mpi/v1"
	"google.golang.org/protobuf/types/known/structpb"
	v1 "k8s.io/api/core/v1"
	"k8s.io/apimachinery/pkg/util/wait"
	"sigs.k8s.io/controller-runtime/pkg/client"

	"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/nginx/agent/broadcast"
	agentgrpc "github.com/nginx/nginx-gateway-fabric/v2/internal/controller/nginx/agent/grpc"
	"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/nginx/types"
	"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/state/dataplane"
	"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/state/resolver"
	"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/status"
)

const retryUpstreamTimeout = 5 * time.Second

//go:generate go tool counterfeiter -generate

//counterfeiter:generate . NginxUpdater

// NginxUpdater is an interface for updating NGINX using the NGINX agent.
type NginxUpdater interface {
	UpdateConfig(deployment *Deployment, files []File, volumeMounts []v1.VolumeMount)
	UpdateUpstreamServers(deployment *Deployment, conf dataplane.Configuration)
}

// NginxUpdaterImpl implements the NginxUpdater interface.
type NginxUpdaterImpl struct {
	CommandService   *commandService
	FileService      *fileService
	NginxDeployments *DeploymentStore
	logger           logr.Logger
	plus             bool
	retryTimeout     time.Duration
}

// NewNginxUpdater returns a new NginxUpdaterImpl instance.
func NewNginxUpdater(
	logger logr.Logger,
	reader client.Reader,
	statusQueue *status.Queue,
	resetConnChan <-chan struct{},
	plus bool,
) *NginxUpdaterImpl {
	connTracker := agentgrpc.NewConnectionsTracker()
	nginxDeployments := NewDeploymentStore(connTracker)

	commandService := newCommandService(
		logger.WithName("commandService"),
		reader,
		nginxDeployments,
		connTracker,
		statusQueue,
		resetConnChan,
	)
	fileService := newFileService(logger.WithName("fileService"), nginxDeployments, connTracker)

	return &NginxUpdaterImpl{
		logger:           logger,
		plus:             plus,
		NginxDeployments: nginxDeployments,
		CommandService:   commandService,
		FileService:      fileService,
		retryTimeout:     retryUpstreamTimeout,
	}
}

// UpdateConfig sends the nginx configuration to the agent.
//
// The flow of events is as follows:
// - Set the configuration files on the deployment.
// - Broadcast the message containing file metadata to all pods (subscriptions) for the deployment.
// - Agent receives a ConfigApplyRequest with the list of file metadata.
// - Agent calls GetFile for each file in the list, which we send back to the agent.
// - Agent updates nginx, and responds with a DataPlaneResponse.
// - Subscriber responds back to the broadcaster to inform that the transaction is complete.
// - If any errors occurred, they are set on the deployment for the handler to use in the status update.
func (n *NginxUpdaterImpl) UpdateConfig(
	deployment *Deployment,
	files []File,
	volumeMounts []v1.VolumeMount,
) {
	msg := deployment.SetFiles(files, volumeMounts)
	if msg == nil {
		n.logger.V(1).Info("No changes to nginx configuration files, not sending to agent")
		return
	}

	applied := deployment.GetBroadcaster().Send(*msg)
	if applied {
		n.logger.Info("Sent nginx configuration to agent")
	}

	deployment.SetLatestConfigError(deployment.GetConfigurationStatus())
}

// UpdateUpstreamServers sends an APIRequest to the agent to update upstream servers using the NGINX Plus API.
// Only applicable when using NGINX Plus.
func (n *NginxUpdaterImpl) UpdateUpstreamServers(
	deployment *Deployment,
	conf dataplane.Configuration,
) {
	if !n.plus {
		return
	}

	broadcaster := deployment.GetBroadcaster()

	// reset the latest error to nil now that we're applying new config
	deployment.SetLatestUpstreamError(nil)

	var errs []error
	var applied bool
	actions := make([]*pb.NGINXPlusAction, 0, len(conf.Upstreams)+len(conf.StreamUpstreams))

	// HTTP/GRPC Upstreams
	for _, upstream := range conf.Upstreams {
		// Skip upstreams that have resolve servers to avoid "UpstreamServerImmutable" errors
		if upstreamHasResolveServers(upstream) {
			continue
		}
		action := &pb.NGINXPlusAction{
			Action: &pb.NGINXPlusAction_UpdateHttpUpstreamServers{
				UpdateHttpUpstreamServers: buildHTTPUpstreamServers(upstream),
			},
		}
		actions = append(actions, action)
	}

	// Stream Upstreams (TLS, TCP, UDP)
	for _, upstream := range conf.StreamUpstreams {
		// Skip upstreams that have resolve servers to avoid "UpstreamServerImmutable" errors
		if upstreamHasResolveServers(upstream) {
			continue
		}
		action := &pb.NGINXPlusAction{
			Action: &pb.NGINXPlusAction_UpdateStreamServers{
				UpdateStreamServers: buildStreamUpstreamServers(upstream),
			},
		}
		actions = append(actions, action)
	}

	if actionsEqual(deployment.GetNGINXPlusActions(), actions) {
		return
	}

	for _, action := range actions {
		msg := broadcast.NginxAgentMessage{
			Type:            broadcast.APIRequest,
			NGINXPlusAction: action,
		}

		requestApplied, err := n.sendRequest(broadcaster, msg, deployment)
		if err != nil {
			errs = append(errs, fmt.Errorf(
				"couldn't update upstream via the API: %w", deployment.GetConfigurationStatus()))
		}
		applied = applied || requestApplied
	}

	if len(errs) != 0 {
		deployment.SetLatestUpstreamError(errors.Join(errs...))
	} else if applied {
		n.logger.Info("Updated upstream servers using NGINX Plus API")
	}

	// Store the most recent actions on the deployment so any new subscribers can apply them when first connecting.
	deployment.SetNGINXPlusActions(actions)
}

func buildHTTPUpstreamServers(upstream dataplane.Upstream) *pb.UpdateHTTPUpstreamServers {
	return &pb.UpdateHTTPUpstreamServers{
		HttpUpstreamName: upstream.Name,
		Servers:          buildUpstreamServers(upstream),
	}
}

func buildStreamUpstreamServers(upstream dataplane.Upstream) *pb.UpdateStreamServers {
	return &pb.UpdateStreamServers{
		UpstreamStreamName: upstream.Name,
		Servers:            buildUpstreamServers(upstream),
	}
}

func buildUpstreamServers(upstream dataplane.Upstream) []*structpb.Struct {
	if len(upstream.Endpoints) == 0 {
		return []*structpb.Struct{
			{
				Fields: map[string]*structpb.Value{
					"server": structpb.NewStringValue(types.Nginx503Server),
				},
			},
		}
	}

	servers := make([]*structpb.Struct, 0, len(upstream.Endpoints))

	for _, endpoint := range upstream.Endpoints {
		port, format := getPortAndIPFormat(endpoint)
		value := fmt.Sprintf(format, endpoint.Address, port)

		server := &structpb.Struct{
			Fields: map[string]*structpb.Value{
				"server": structpb.NewStringValue(value),
			},
		}

		servers = append(servers, server)
	}

	// sort the servers to avoid unnecessary reloads
	sort.Slice(servers, func(i, j int) bool {
		return servers[i].Fields["server"].GetStringValue() < servers[j].Fields["server"].GetStringValue()
	})

	return servers
}

func (n *NginxUpdaterImpl) sendRequest(
	broadcaster broadcast.Broadcaster,
	msg broadcast.NginxAgentMessage,
	deployment *Deployment,
) (bool, error) {
	// retry the API update request because sometimes nginx isn't quite ready after the config apply reload
	ctx, cancel := context.WithTimeout(context.Background(), n.retryTimeout)
	defer cancel()

	var applied bool
	if err := wait.PollUntilContextCancel(
		ctx,
		500*time.Millisecond,
		true, // poll immediately
		func(_ context.Context) (bool, error) {
			applied = broadcaster.Send(msg)
			if statusErr := deployment.GetConfigurationStatus(); statusErr != nil {
				return false, nil //nolint:nilerr // will get error once done polling
			}

			return true, nil
		},
	); err != nil {
		return applied, err
	}

	return applied, nil
}

// upstreamHasResolveServers checks if an upstream contains servers that require DNS resolution.
func upstreamHasResolveServers(upstream dataplane.Upstream) bool {
	for _, endpoint := range upstream.Endpoints {
		if endpoint.Resolve {
			return true
		}
	}
	return false
}

func getPortAndIPFormat(ep resolver.Endpoint) (string, string) {
	var port string

	if ep.Port != 0 {
		port = fmt.Sprintf(":%d", ep.Port)
	}

	format := "%s%s"
	if ep.IPv6 {
		format = "[%s]%s"
	}

	return port, format
}

package grpc

import (
	"context"
	"crypto/tls"
	"crypto/x509"
	"errors"
	"fmt"
	"net"
	"os"
	"time"

	"github.com/go-logr/logr"
	"google.golang.org/grpc"
	"google.golang.org/grpc/codes"
	"google.golang.org/grpc/credentials"
	"google.golang.org/grpc/keepalive"
	"google.golang.org/grpc/status"
	"sigs.k8s.io/controller-runtime/pkg/client"
	"sigs.k8s.io/controller-runtime/pkg/manager"

	"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/nginx/agent/grpc/filewatcher"
	"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/nginx/agent/grpc/interceptor"
	"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/state/graph/shared/secrets"
)

const (
	keepAliveTime    = 15 * time.Second
	keepAliveTimeout = 10 * time.Second
	caCertPath       = "/var/run/secrets/ngf/" + secrets.CAKey
	tlsCertPath      = "/var/run/secrets/ngf/" + secrets.TLSCertKey
	tlsKeyPath       = "/var/run/secrets/ngf/" + secrets.TLSKeyKey
)

var ErrStatusInvalidConnection = status.Error(codes.Unauthenticated, "invalid connection")

// Interceptor provides hooks to intercept the execution of an RPC on the server.
type Interceptor interface {
	Stream(logr.Logger) grpc.StreamServerInterceptor
	Unary(logr.Logger) grpc.UnaryServerInterceptor
}

// Server is a gRPC server for communicating with the nginx agent.
type Server struct {
	// Interceptor provides hooks to intercept the execution of an RPC on the server.
	interceptor Interceptor

	logger logr.Logger

	// resetConnChan is used by the filewatcher to trigger the Command service to
	// reset any connections when TLS files are updated.
	resetConnChan chan<- struct{}
	// RegisterServices is a list of functions to register gRPC services to the gRPC server.
	registerServices []func(*grpc.Server)
	// Port is the port that the server is listening on.
	// Must be exposed in the control plane deployment/service.
	port int
}

func NewServer(
	logger logr.Logger,
	port int,
	registerSvcs []func(*grpc.Server),
	k8sClient client.Client,
	tokenAudience string,
	resetConnChan chan<- struct{},
) *Server {
	return &Server{
		logger:           logger,
		port:             port,
		registerServices: registerSvcs,
		interceptor:      interceptor.NewContextSetter(k8sClient, tokenAudience),
		resetConnChan:    resetConnChan,
	}
}

// Start is a runnable that starts the gRPC server for communicating with the nginx agent.
func (g *Server) Start(ctx context.Context) error {
	var lc net.ListenConfig
	listener, err := lc.Listen(ctx, "tcp", fmt.Sprintf(":%d", g.port))
	if err != nil {
		return err
	}

	tlsCredentials, err := getTLSConfig()
	if err != nil {
		return err
	}

	server := g.createServer(tlsCredentials)

	for _, registerSvc := range g.registerServices {
		registerSvc(server)
	}

	tlsFiles := []string{caCertPath, tlsCertPath, tlsKeyPath}
	fileWatcher, err := filewatcher.NewFileWatcher(g.logger.WithName("fileWatcher"), tlsFiles, g.resetConnChan)
	if err != nil {
		return err
	}

	go fileWatcher.Watch(ctx)

	go func() {
		<-ctx.Done()
		g.logger.Info("Shutting down GRPC Server")
		// Since we use a long-lived stream, GracefulStop does not terminate. Therefore we use Stop.
		server.Stop()
	}()

	return server.Serve(listener)
}

func (g *Server) createServer(tlsCredentials credentials.TransportCredentials) *grpc.Server {
	server := grpc.NewServer(
		grpc.KeepaliveParams(
			keepalive.ServerParameters{
				Time:    keepAliveTime,
				Timeout: keepAliveTimeout,
			},
		),
		grpc.KeepaliveEnforcementPolicy(
			keepalive.EnforcementPolicy{
				MinTime:             keepAliveTime,
				PermitWithoutStream: true,
			},
		),
		grpc.ChainStreamInterceptor(g.interceptor.Stream(g.logger)),
		grpc.ChainUnaryInterceptor(g.interceptor.Unary(g.logger)),
		grpc.Creds(tlsCredentials),
		// Set max message size to 4MB to match the agent side.
		grpc.MaxSendMsgSize(1024*1024*4), // 4MB
		grpc.MaxRecvMsgSize(1024*1024*4), // 4MB
	)

	return server
}

func getTLSConfig() (credentials.TransportCredentials, error) {
	return buildTLSCredentials(caCertPath, tlsCertPath, tlsKeyPath)
}

// buildTLSCredentials creates mTLS transport credentials that dynamically reload TLS files on
// each new connection. The CA cert pool and server certificate are read from disk for every
// incoming TLS handshake via GetConfigForClient, so that certificate rotations (e.g., from the
// cert-generator Helm pre-upgrade job) take effect without a control plane restart.
//
// caPath, certPath, and keyPath are validated on startup; if any file is missing or unparseable
// the function returns an error before the server starts accepting connections.
func buildTLSCredentials(caPath, certPath, keyPath string) (credentials.TransportCredentials, error) {
	// Validate that the initial TLS files exist and are parseable.
	if _, err := loadCACertPool(caPath); err != nil {
		return nil, err
	}
	if _, err := tls.LoadX509KeyPair(certPath, keyPath); err != nil {
		return nil, err
	}

	tlsConfig := &tls.Config{
		GetConfigForClient: buildConfigForClient(caPath, certPath, keyPath),
		MinVersion:         tls.VersionTLS13,
	}

	return credentials.NewTLS(tlsConfig), nil
}

// buildConfigForClient returns a GetConfigForClient callback that builds a fresh tls.Config
// for each incoming connection by reading the CA cert pool and server certificate from disk.
func buildConfigForClient(caPath, certPath, keyPath string) func(*tls.ClientHelloInfo) (*tls.Config, error) {
	return func(_ *tls.ClientHelloInfo) (*tls.Config, error) {
		certPool, err := loadCACertPool(caPath)
		if err != nil {
			return nil, err
		}

		return &tls.Config{
			GetCertificate: func(_ *tls.ClientHelloInfo) (*tls.Certificate, error) {
				serverCert, err := tls.LoadX509KeyPair(certPath, keyPath)
				if err != nil {
					return nil, err
				}
				return &serverCert, nil
			},
			ClientAuth: tls.RequireAndVerifyClientCert,
			ClientCAs:  certPool,
			MinVersion: tls.VersionTLS13,
		}, nil
	}
}

// loadCACertPool reads the CA certificate from the given path and returns a new CertPool.
func loadCACertPool(caPath string) (*x509.CertPool, error) {
	caPem, err := os.ReadFile(caPath)
	if err != nil {
		return nil, fmt.Errorf("error reading CA cert: %w", err)
	}

	certPool := x509.NewCertPool()
	if !certPool.AppendCertsFromPEM(caPem) {
		return nil, errors.New("error parsing CA PEM")
	}

	return certPool, nil
}

var _ manager.Runnable = &Server{}

package grpc

import (
	"sync"

	"k8s.io/apimachinery/pkg/types"
)

//go:generate go tool counterfeiter -generate

//counterfeiter:generate . ConnectionsTracker

// ConnectionsTracker defines an interface to track all connections between the control plane
// and nginx agents.
type ConnectionsTracker interface {
	Track(key string, conn Connection)
	GetConnection(key string) Connection
	SetInstanceID(key, id string)
	RemoveConnection(key string)
}

// Connection contains the data about a single nginx agent connection.
type Connection struct {
	InstanceID string
	ParentType string
	ParentName types.NamespacedName
}

// Ready returns if the connection is ready to be used. In other words, agent
// has registered itself and an nginx instance with the control plane.
func (c *Connection) Ready() bool {
	return c.InstanceID != ""
}

// AgentConnectionsTracker keeps track of all connections between the control plane and nginx agents.
type AgentConnectionsTracker struct {
	// connections contains a map of all IP addresses that have connected and their connection info.
	connections map[string]Connection

	lock sync.RWMutex
}

// NewConnectionsTracker returns a new AgentConnectionsTracker instance.
func NewConnectionsTracker() ConnectionsTracker {
	return &AgentConnectionsTracker{
		connections: make(map[string]Connection),
	}
}

// Track adds a connection to the tracking map.
func (c *AgentConnectionsTracker) Track(key string, conn Connection) {
	c.lock.Lock()
	defer c.lock.Unlock()

	c.connections[key] = conn
}

// GetConnection returns the requested connection.
func (c *AgentConnectionsTracker) GetConnection(key string) Connection {
	c.lock.RLock()
	defer c.lock.RUnlock()

	return c.connections[key]
}

// SetInstanceID sets the nginx instanceID for a connection.
func (c *AgentConnectionsTracker) SetInstanceID(key, id string) {
	c.lock.Lock()
	defer c.lock.Unlock()

	if conn, ok := c.connections[key]; ok {
		conn.InstanceID = id
		c.connections[key] = conn
	}
}

// RemoveConnection removes a connection from the tracking map.
func (c *AgentConnectionsTracker) RemoveConnection(key string) {
	c.lock.Lock()
	defer c.lock.Unlock()

	delete(c.connections, key)
}

package broadcast

import (
	"context"
	"sync"

	pb "github.com/nginx/agent/v3/api/grpc/mpi/v1"
	"k8s.io/apimachinery/pkg/util/uuid"
)

//go:generate go tool counterfeiter -generate

//counterfeiter:generate . Broadcaster

// Broadcaster defines an interface for consumers to subscribe to File updates.
type Broadcaster interface {
	Subscribe() SubscriberChannels
	Send(NginxAgentMessage) bool
	CancelSubscription(string)
}

// SubscriberChannels are the channels sent to the subscriber to listen and respond on.
// The ID is used for map lookup to delete a subscriber when it's gone.
type SubscriberChannels struct {
	ListenCh   <-chan NginxAgentMessage
	ResponseCh chan<- struct{}
	ID         string
}

// storedChannels are the same channels used in the SubscriberChannels, but reverse direction.
// These are used to store the channels for the broadcaster to send and listen on,
// and can be looked up in the map using the same ID.
type storedChannels struct {
	listenCh chan<- NginxAgentMessage
	// responseCh is only received from by the broadcaster; subscribers send on it to signal completion.
	responseCh <-chan struct{}
	// listenerCtx is used to unblock the publisher if a listener unsubscribes or if the broadcaster is shutting
	// down. It is a child of the broadcaster context, so it will also be canceled on shutdown.
	listenerCtx context.Context
	cancel      context.CancelFunc
	id          string
}

// DeploymentBroadcaster sends out a signal when an nginx Deployment has updated
// configuration files. The signal is received by any agent Subscription that cares
// about this Deployment. The agent Subscription will then send a response of whether or not
// the configuration was successfully applied.
type DeploymentBroadcaster struct {
	publishCh chan NginxAgentMessage
	subCh     chan storedChannels
	unsubCh   chan string
	listeners map[string]storedChannels
	doneCh    chan struct{}
	// broadcasterCtx is the main context for the broadcaster, which is canceled on shutdown.
	// It is the parent context for all listener contexts.
	broadcasterCtx    context.Context
	broadcasterCancel context.CancelFunc
	// mu protects the listeners map. It is needed for concurrent access to
	// the listeners map in the publisher and subscriber goroutines.
	mu sync.RWMutex
}

// NewDeploymentBroadcaster returns a new instance of a DeploymentBroadcaster.
func NewDeploymentBroadcaster(ctx context.Context) *DeploymentBroadcaster {
	broadcasterCtx, broadcasterCancel := context.WithCancel(ctx)

	broadcaster := &DeploymentBroadcaster{
		listeners:         make(map[string]storedChannels),
		publishCh:         make(chan NginxAgentMessage),
		subCh:             make(chan storedChannels),
		unsubCh:           make(chan string),
		doneCh:            make(chan struct{}),
		broadcasterCtx:    broadcasterCtx,
		broadcasterCancel: broadcasterCancel,
	}

	go broadcaster.subscriber()
	go broadcaster.publisher()

	return broadcaster
}

// Subscribe allows a listener to subscribe to broadcast messages. It returns the channel
// to listen on for messages, as well as a channel to respond on.
func (b *DeploymentBroadcaster) Subscribe() SubscriberChannels {
	listenCh := make(chan NginxAgentMessage)
	responseCh := make(chan struct{})
	id := string(uuid.NewUUID())
	// Create listener context as child of broadcaster context

	listenerCtx, cancel := context.WithCancel(b.broadcasterCtx)

	subscriberChans := SubscriberChannels{
		ID:         id,
		ListenCh:   listenCh,
		ResponseCh: responseCh,
	}
	storedChans := storedChannels{
		id:          id,
		listenCh:    listenCh,
		responseCh:  responseCh,
		listenerCtx: listenerCtx,
		cancel:      cancel,
	}

	select {
	case <-b.broadcasterCtx.Done():
		// Broadcaster is shutting down or already shut down. Returns channels so the caller
		// can still interact with them while shutting down.
		return subscriberChans
	case b.subCh <- storedChans:
		// Subscription sent successfully
	}

	return subscriberChans
}

// Send the message to all listeners. Wait for all listeners to respond.
// Returns true if there were listeners that received and responded to the message.
func (b *DeploymentBroadcaster) Send(message NginxAgentMessage) bool {
	// Try to send message, but can be interrupted by shutdown
	select {
	case b.publishCh <- message:
	case <-b.broadcasterCtx.Done():
		return false
	}

	// Wait for completion, but can be interrupted by shutdown
	select {
	case <-b.doneCh:
	case <-b.broadcasterCtx.Done():
		return false
	}

	b.mu.RLock()
	defer b.mu.RUnlock()

	return len(b.listeners) > 0
}

// CancelSubscription removes a Subscriber from the channel list.
func (b *DeploymentBroadcaster) CancelSubscription(id string) {
	select {
	case b.unsubCh <- id:
	case <-b.broadcasterCtx.Done():
		// Broadcaster is shutting down or already shut down; avoid blocking send.
		return
	}
}

// subscriber handles subscription management and stop conditions. It is responsible for cleaning up resources
// on shutdown/function return, specifically by canceling the broadcaster context (and thus all listener
// contexts) to unblock any pending publisher goroutines.
func (b *DeploymentBroadcaster) subscriber() {
	// Canceling the broadcaster context will cancel all listener contexts since they are children,
	// which will unblock any publishers waiting on those contexts.
	defer b.broadcasterCancel()

	for {
		select {
		case <-b.broadcasterCtx.Done():
			return
		case channels := <-b.subCh:
			b.mu.Lock()
			b.listeners[channels.id] = channels
			b.mu.Unlock()
		case id := <-b.unsubCh:
			b.mu.Lock()
			if channels, exists := b.listeners[id]; exists {
				// Cancel listener's context to unblock publisher
				channels.cancel()
				delete(b.listeners, id)
			}
			b.mu.Unlock()
		}
	}
}

// publisher handles message publishing.
func (b *DeploymentBroadcaster) publisher() {
	// Due to the split between the subscription management and publishing,
	// every blocking select in this function needs a way to be unblocked
	// by the subscriber function.
	for {
		select {
		case <-b.broadcasterCtx.Done():
			return
		case msg := <-b.publishCh:
			b.mu.RLock()
			currentListeners := make(map[string]storedChannels, len(b.listeners))
			for k, v := range b.listeners {
				currentListeners[k] = v
			}
			b.mu.RUnlock()

			// Send to all listeners
			var wg sync.WaitGroup
			for _, channels := range currentListeners {
				wg.Go(func() {
					select {
					case <-channels.listenerCtx.Done():
						return
					case <-b.broadcasterCtx.Done():
						return
					case channels.listenCh <- msg:
						// Message sent successfully, now wait for response in next select
					}

					select {
					case <-channels.listenerCtx.Done():
						return
					case <-b.broadcasterCtx.Done():
						return
					case <-channels.responseCh:
						// Response received, continue
						return
					}
				})
			}
			wg.Wait()

			select {
			// If the broadcaster context is done, there may be nothing to receive
			// the done signal, so we return to avoid blocking.
			case <-b.broadcasterCtx.Done():
				return
			case b.doneCh <- struct{}{}:
				// Signal that publishing is done and all responses received
			}
		}
	}
}

// MessageType is the type of message to be sent.
type MessageType int

const (
	// ConfigApplyRequest sends files to update nginx configuration.
	ConfigApplyRequest MessageType = iota
	// APIRequest sends an NGINX Plus API request to update configuration.
	APIRequest
)

// NginxAgentMessage is sent to all subscribers to send to the nginx agents for either a ConfigApplyRequest
// or an APIActionRequest.
type NginxAgentMessage struct {
	// ConfigVersion is the hashed configuration version of the included files.
	ConfigVersion string
	// NGINXPlusAction is an NGINX Plus API action to be sent.
	NGINXPlusAction *pb.NGINXPlusAction
	// FileOverviews contain the overviews of all files to be sent.
	FileOverviews []*pb.File
	// Type defines the type of message to be sent.
	Type MessageType
}

package agent

import (
	"bytes"
	"context"
	"math"

	"github.com/go-logr/logr"
	pb "github.com/nginx/agent/v3/api/grpc/mpi/v1"
	"github.com/nginx/agent/v3/pkg/files"
	"google.golang.org/grpc"
	"google.golang.org/grpc/codes"
	"google.golang.org/grpc/status"

	agentgrpc "github.com/nginx/nginx-gateway-fabric/v2/internal/controller/nginx/agent/grpc"
	grpcContext "github.com/nginx/nginx-gateway-fabric/v2/internal/controller/nginx/agent/grpc/context"
)

const defaultChunkSize uint32 = 2097152 // 2MB

// File is an nginx configuration file that the nginx agent gets from the control plane
// after a ConfigApplyRequest.
type File struct {
	Meta     *pb.FileMeta
	Contents []byte
}

// fileService handles file management between the control plane and the agent.
type fileService struct {
	pb.FileServiceServer
	nginxDeployments *DeploymentStore
	connTracker      agentgrpc.ConnectionsTracker
	logger           logr.Logger
}

func newFileService(
	logger logr.Logger,
	depStore *DeploymentStore,
	connTracker agentgrpc.ConnectionsTracker,
) *fileService {
	return &fileService{
		logger:           logger,
		nginxDeployments: depStore,
		connTracker:      connTracker,
	}
}

func (fs *fileService) Register(server *grpc.Server) {
	pb.RegisterFileServiceServer(server, fs)
}

// GetFile is called by the agent when it needs to download a file for a ConfigApplyRequest.
// The deployment object used to get the files is already LOCKED when this function is called,
// before the ConfigApply transaction is started.
func (fs *fileService) GetFile(
	ctx context.Context,
	req *pb.GetFileRequest,
) (*pb.GetFileResponse, error) {
	grpcInfo, ok := grpcContext.FromContext(ctx)
	if !ok {
		return nil, agentgrpc.ErrStatusInvalidConnection
	}

	if req.GetFileMeta() == nil {
		return nil, status.Error(codes.InvalidArgument, "invalid request")
	}

	contents, err := fs.getFileContents(req, grpcInfo.UUID)
	if err != nil {
		return nil, err
	}

	return &pb.GetFileResponse{
		Contents: &pb.FileContents{
			Contents: contents,
		},
	}, nil
}

// GetFileStream is called by the agent when it needs to download a file in chunks for a ConfigApplyRequest.
// The deployment object used to get the files is already LOCKED when this function is called,
// before the ConfigApply transaction is started.
func (fs *fileService) GetFileStream(
	req *pb.GetFileRequest,
	server grpc.ServerStreamingServer[pb.FileDataChunk],
) error {
	grpcInfo, ok := grpcContext.FromContext(server.Context())
	if !ok {
		return agentgrpc.ErrStatusInvalidConnection
	}

	if req.GetFileMeta() == nil || req.GetMessageMeta() == nil {
		return status.Error(codes.InvalidArgument, "invalid request")
	}

	contents, err := fs.getFileContents(req, grpcInfo.UUID)
	if err != nil {
		return err
	}

	size := req.GetFileMeta().GetSize()
	var sizeUint32 uint32
	if size > math.MaxUint32 {
		return status.Error(codes.Internal, "file size is too large and cannot be converted to uint32")
	}
	sizeUint32 = uint32(size) //nolint:gosec // validation check performed on previous line
	hash := req.GetFileMeta().GetHash()

	fs.logger.V(1).Info(
		"Sending chunked file to agent",
		"file", req.GetFileMeta().GetName(),
		"correlation_id", req.GetMessageMeta().GetCorrelationId(),
	)

	if err := files.SendChunkedFile(
		req.GetMessageMeta(),
		pb.FileDataChunk_Header{
			Header: &pb.FileDataChunkHeader{
				ChunkSize: defaultChunkSize,
				Chunks:    calculateChunks(sizeUint32, defaultChunkSize),
				FileMeta: &pb.FileMeta{
					Name:        req.GetFileMeta().GetName(),
					Hash:        hash,
					Permissions: req.GetFileMeta().GetPermissions(),
					Size:        size,
				},
			},
		},
		bytes.NewReader(contents),
		server,
	); err != nil {
		return status.Error(codes.Aborted, err.Error())
	}

	return nil
}

func (fs *fileService) getFileContents(req *pb.GetFileRequest, connKey string) ([]byte, error) {
	conn := fs.connTracker.GetConnection(connKey)
	if conn.InstanceID == "" {
		return nil, status.Errorf(codes.Internal, "connection not found")
	}

	deployment := fs.nginxDeployments.Get(conn.ParentName)
	if deployment == nil {
		return nil, status.Errorf(codes.Internal, "deployment not found in store")
	}

	filename := req.GetFileMeta().GetName()
	contents, fileFoundHash := deployment.GetFile(filename, req.GetFileMeta().GetHash())
	if len(contents) == 0 {
		fs.logger.V(1).Info(
			"Error getting file for agent",
			"file", filename,
			"correlation_id", req.GetMessageMeta().GetCorrelationId(),
		)
		if fileFoundHash != "" {
			fs.logger.V(1).Info(
				"File found had wrong hash",
				"hash_wanted", req.GetFileMeta().GetHash(),
				"hash_found", fileFoundHash,
				"correlation_id", req.GetMessageMeta().GetCorrelationId(),
			)
		}
		return nil, status.Errorf(codes.NotFound, "file not found")
	}

	fs.logger.V(1).Info(
		"Getting file for agent",
		"file", filename,
		"file_hash", fileFoundHash,
		"correlation_id", req.GetMessageMeta().GetCorrelationId(),
	)

	return contents, nil
}

func calculateChunks(fileSize uint32, chunkSize uint32) uint32 {
	remainder, divide := fileSize%chunkSize, fileSize/chunkSize
	if remainder > 0 {
		return divide + 1
	}
	// if fileSize is divisible by chunkSize without remainder
	// then we don't need the extra chunk for the remainder
	return divide
}

// GetOverview gets the overview of files for a particular configuration version of an instance.
// At the moment it doesn't appear to be used by the agent.
func (*fileService) GetOverview(context.Context, *pb.GetOverviewRequest) (*pb.GetOverviewResponse, error) {
	return &pb.GetOverviewResponse{}, nil
}

// UpdateOverview is called by agent on startup and whenever any files change on the instance.
// Since directly changing nginx configuration on the instance is not supported, NGF will send back an empty response.
// However, we do use this call to gather the list of referenced files in the nginx configuration in order to
// mark user mounted files as unmanaged so the agent does not attempt to modify them.
func (fs *fileService) UpdateOverview(
	ctx context.Context,
	req *pb.UpdateOverviewRequest,
) (*pb.UpdateOverviewResponse, error) {
	grpcInfo, ok := grpcContext.FromContext(ctx)
	if !ok {
		return &pb.UpdateOverviewResponse{}, agentgrpc.ErrStatusInvalidConnection
	}

	conn := fs.connTracker.GetConnection(grpcInfo.UUID)
	if conn.InstanceID == "" {
		return &pb.UpdateOverviewResponse{}, status.Errorf(codes.Internal, "connection not found")
	}

	deployment := fs.nginxDeployments.Get(conn.ParentName)
	if deployment == nil {
		return &pb.UpdateOverviewResponse{}, status.Errorf(codes.Internal, "deployment not found in store")
	}

	requestFiles := req.GetOverview().GetFiles()

	fileNames := make([]string, 0, len(requestFiles))
	for _, f := range requestFiles {
		fileNames = append(fileNames, f.GetFileMeta().GetName())
	}

	deployment.FileLock.Lock()
	deployment.latestFileNames = fileNames
	deployment.FileLock.Unlock()

	return &pb.UpdateOverviewResponse{}, nil
}

// UpdateFile is called by agent whenever any files change on the instance.
// Since directly changing nginx configuration on the instance is not supported, this is a no-op for NGF.
func (*fileService) UpdateFile(context.Context, *pb.UpdateFileRequest) (*pb.UpdateFileResponse, error) {
	return &pb.UpdateFileResponse{}, nil
}

// UpdateFileStream is called by agent whenever any files change on the instance.
// Since directly changing nginx configuration on the instance is not supported, this is a no-op for NGF.
func (*fileService) UpdateFileStream(grpc.ClientStreamingServer[pb.FileDataChunk, pb.UpdateFileResponse]) error {
	return nil
}

package agent

import (
	"context"
	"errors"
	"fmt"
	"strings"
	"sync"

	pb "github.com/nginx/agent/v3/api/grpc/mpi/v1"
	filesHelper "github.com/nginx/agent/v3/pkg/files"
	v1 "k8s.io/api/core/v1"
	"k8s.io/apimachinery/pkg/types"

	"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/nginx/agent/broadcast"
	agentgrpc "github.com/nginx/nginx-gateway-fabric/v2/internal/controller/nginx/agent/grpc"
)

// ignoreFiles is a list of static or base files that live in the
// nginx container that should not be touched by the agent. Any files
// that we add directly into the container should be added here.
var ignoreFiles = []string{
	"/etc/nginx/nginx.conf",
	"/etc/nginx/mime.types",
	"/etc/nginx/grpc-error-locations.conf",
	"/etc/nginx/grpc-error-pages.conf",
	"/usr/share/nginx/html/50x.html",
	"/usr/share/nginx/html/dashboard.html",
	"/usr/share/nginx/html/index.html",
	"/usr/share/nginx/html/nginx-modules-reference.pdf",
}

const fileMode = "0644"

// Deployment represents an nginx Deployment. It contains its own nginx configuration files,
// a broadcaster for sending those files to all of its pods that are subscribed, and errors
// that may have occurred while applying configuration.
type Deployment struct {
	// podStatuses is a map of all Pods for this Deployment and the most recent error
	// (or nil if successful) that occurred on a config call to the nginx agent.
	podStatuses map[string]error

	broadcaster broadcast.Broadcaster

	// gatewayName is the name of the Gateway associated with this Deployment.
	gatewayName string

	imageVersion string

	configVersion string
	// error that is set if a ConfigApply call failed for a Pod. This is needed
	// because if subsequent upstream API calls are made within the same update event,
	// and are successful, the previous error would be lost in the podStatuses map.
	// It's used to preserve the error for when we write status after fully updating nginx.
	latestConfigError error
	// error that is set when at least one upstream API call failed for a Pod.
	// This is needed because subsequent API calls within the same update event could succeed,
	// and therefore the previous error would be lost in the podStatuses map. It's used to preserve
	// the error for when we write status after fully updating nginx.
	latestUpstreamError error

	nginxPlusActions []*pb.NGINXPlusAction
	fileOverviews    []*pb.File
	files            []File

	latestFileNames []string
	volumeMounts    []v1.VolumeMount

	FileLock sync.RWMutex
	errLock  sync.RWMutex
}

// newDeployment returns a new Deployment object.
func newDeployment(broadcaster broadcast.Broadcaster, gatewayName string) *Deployment {
	return &Deployment{
		broadcaster: broadcaster,
		podStatuses: make(map[string]error),
		gatewayName: gatewayName,
	}
}

// GetGatewayName returns the name of the Gateway associated with this deployment.
func (d *Deployment) GetGatewayName() string {
	return d.gatewayName
}

// GetBroadcaster returns the deployment's broadcaster.
func (d *Deployment) GetBroadcaster() broadcast.Broadcaster {
	return d.broadcaster
}

// SetImageVersion sets the deployment's image version.
func (d *Deployment) SetImageVersion(imageVersion string) {
	d.FileLock.Lock()
	defer d.FileLock.Unlock()

	d.imageVersion = imageVersion
}

// SetLatestConfigError sets the latest config apply error for the deployment.
func (d *Deployment) SetLatestConfigError(err error) {
	d.errLock.Lock()
	defer d.errLock.Unlock()

	d.latestConfigError = err
}

// SetLatestUpstreamError sets the latest upstream update error for the deployment.
func (d *Deployment) SetLatestUpstreamError(err error) {
	d.errLock.Lock()
	defer d.errLock.Unlock()

	d.latestUpstreamError = err
}

// GetLatestConfigError gets the latest config apply error for the deployment.
func (d *Deployment) GetLatestConfigError() error {
	d.errLock.RLock()
	defer d.errLock.RUnlock()

	return d.latestConfigError
}

// GetLatestUpstreamError gets the latest upstream update error for the deployment.
func (d *Deployment) GetLatestUpstreamError() error {
	d.errLock.RLock()
	defer d.errLock.RUnlock()

	return d.latestUpstreamError
}

// SetPodErrorStatus sets the error status of a Pod in this Deployment if applying the config failed.
func (d *Deployment) SetPodErrorStatus(pod string, err error) {
	d.errLock.Lock()
	defer d.errLock.Unlock()

	d.podStatuses[pod] = err
}

// RemovePodStatus deletes a pod from the pod status map.
func (d *Deployment) RemovePodStatus(podName string) {
	d.errLock.Lock()
	defer d.errLock.Unlock()

	delete(d.podStatuses, podName)
}

// GetConfigurationStatus returns the current config status for this Deployment. It combines
// the most recent errors (if they exist) for all Pods in the Deployment into a single error.
func (d *Deployment) GetConfigurationStatus() error {
	d.errLock.RLock()
	defer d.errLock.RUnlock()

	errs := make([]error, 0, len(d.podStatuses))
	for _, err := range d.podStatuses {
		errs = append(errs, err)
	}

	if len(errs) == 1 {
		return errs[0]
	}

	return errors.Join(errs...)
}

/*
The following functions for the Deployment object are UNLOCKED, meaning that they are unsafe.
Callers of these functions MUST ensure the FileLock is set before calling.

These functions are called as part of the ConfigApply or APIRequest processes. These entire processes
are locked by the caller, hence why the functions themselves do not set the locks.
*/

// GetFileOverviews returns the current list of fileOverviews and configVersion for the deployment.
// The deployment FileLock MUST already be locked before calling this function.
func (d *Deployment) GetFileOverviews() ([]*pb.File, string) {
	return d.fileOverviews, d.configVersion
}

// GetNGINXPlusActions returns the current NGINX Plus API Actions for the deployment.
// The deployment FileLock MUST already be locked before calling this function.
func (d *Deployment) GetNGINXPlusActions() []*pb.NGINXPlusAction {
	return d.nginxPlusActions
}

// GetFile gets the requested file for the deployment and returns its contents.
// The deployment FileLock MUST already be locked before calling this function.
func (d *Deployment) GetFile(name, hash string) ([]byte, string) {
	var fileFoundHash string
	for _, file := range d.files {
		if name == file.Meta.GetName() {
			fileFoundHash = file.Meta.GetHash()
			if hash == file.Meta.GetHash() {
				return file.Contents, file.Meta.GetHash()
			}
		}
	}

	return nil, fileFoundHash
}

// SetFiles updates the nginx files and fileOverviews for the deployment and returns the message to send.
// The deployment FileLock MUST already be locked before calling this function.
func (d *Deployment) SetFiles(files []File, volumeMounts []v1.VolumeMount) *broadcast.NginxAgentMessage {
	d.files = files
	d.volumeMounts = volumeMounts

	return d.rebuildFileOverviews()
}

// SetNGINXPlusActions updates the deployment's latest NGINX Plus Actions to perform if using NGINX Plus.
// Used by a Subscriber when it first connects.
// The deployment FileLock MUST already be locked before calling this function.
func (d *Deployment) SetNGINXPlusActions(actions []*pb.NGINXPlusAction) {
	d.nginxPlusActions = actions
}

// UpdateWAFBundle replaces or inserts a WAF bundle file in the deployment's file list.
// It finds an existing file by its full path and replaces its contents and metadata,
// or appends a new file entry if the bundle does not yet exist.
// Returns a broadcast message if the config version changed (i.e. the bundle contents differ
// from what was previously stored), or nil if nothing changed.
// The deployment FileLock MUST already be locked before calling this function.
func (d *Deployment) UpdateWAFBundle(bundlePath string, data []byte) *broadcast.NginxAgentMessage {
	newHash := filesHelper.GenerateHash(data)
	newMeta := &pb.FileMeta{
		Name:        bundlePath,
		Hash:        newHash,
		Permissions: fileMode,
		Size:        int64(len(data)),
	}

	found := false
	for i, f := range d.files {
		if f.Meta.GetName() == bundlePath {
			d.files[i] = File{
				Meta:     newMeta,
				Contents: data,
			}
			found = true
			break
		}
	}

	if !found {
		d.files = append(d.files, File{
			Meta:     newMeta,
			Contents: data,
		})
	}

	return d.rebuildFileOverviews()
}

// RemoveWAFBundle removes a WAF bundle file from the deployment's file list.
// Returns a broadcast message if the config version changed, or nil if the bundle
// was not found or nothing changed.
// The deployment FileLock MUST already be locked before calling this function.
func (d *Deployment) RemoveWAFBundle(bundlePath string) *broadcast.NginxAgentMessage {
	for i, f := range d.files {
		if f.Meta.GetName() == bundlePath {
			d.files = append(d.files[:i], d.files[i+1:]...)
			return d.rebuildFileOverviews()
		}
	}
	return nil
}

// rebuildFileOverviews regenerates the file overviews and config version from the current
// file list. Returns a broadcast message if the config version changed.
// The deployment FileLock MUST already be locked before calling this function.
func (d *Deployment) rebuildFileOverviews() *broadcast.NginxAgentMessage {
	fileOverviews := make([]*pb.File, 0, len(d.files))
	for _, f := range d.files {
		fileOverviews = append(fileOverviews, &pb.File{FileMeta: f.Meta})
	}

	// Build the set of unmanaged files from volume mounts.
	fileIgnoreSet := make(map[string]struct{})
	for _, vm := range d.volumeMounts {
		for _, f := range d.latestFileNames {
			if strings.HasPrefix(f, vm.MountPath) {
				fileIgnoreSet[f] = struct{}{}
			}
		}
	}

	// Add static and volume-mount ignored files as 'unmanaged' so agent doesn't touch them.
	for _, f := range ignoreFiles {
		fileIgnoreSet[f] = struct{}{}
	}

	for f := range fileIgnoreSet {
		fileOverviews = append(fileOverviews, &pb.File{
			FileMeta: &pb.FileMeta{
				Name:        f,
				Permissions: fileMode,
			},
			Unmanaged: true,
		})
	}

	newConfigVersion := filesHelper.GenerateConfigVersion(fileOverviews)
	if d.configVersion == newConfigVersion {
		// files have not changed, nothing to send
		return nil
	}

	d.configVersion = newConfigVersion
	d.fileOverviews = fileOverviews

	return &broadcast.NginxAgentMessage{
		Type:          broadcast.ConfigApplyRequest,
		FileOverviews: fileOverviews,
		ConfigVersion: d.configVersion,
	}
}

//counterfeiter:generate . DeploymentStorer

// DeploymentStorer is an interface to store Deployments.
type DeploymentStorer interface {
	Get(types.NamespacedName) *Deployment
	GetOrStore(context.Context, types.NamespacedName, string) *Deployment
	Remove(types.NamespacedName)
}

// DeploymentStore holds a map of all Deployments.
type DeploymentStore struct {
	connTracker agentgrpc.ConnectionsTracker
	deployments sync.Map
}

// NewDeploymentStore returns a new instance of a DeploymentStore.
func NewDeploymentStore(connTracker agentgrpc.ConnectionsTracker) *DeploymentStore {
	return &DeploymentStore{
		connTracker: connTracker,
	}
}

// Get returns the desired deployment from the store.
func (d *DeploymentStore) Get(nsName types.NamespacedName) *Deployment {
	val, ok := d.deployments.Load(nsName)
	if !ok {
		return nil
	}

	deployment, ok := val.(*Deployment)
	if !ok {
		panic(fmt.Sprintf("expected Deployment, got type %T", val))
	}

	return deployment
}

// GetOrStore returns the existing value for the key if present.
// Otherwise, it stores and returns the given value.
func (d *DeploymentStore) GetOrStore(
	ctx context.Context,
	nsName types.NamespacedName,
	gatewayName string,
) *Deployment {
	if deployment := d.Get(nsName); deployment != nil {
		return deployment
	}

	deployment := newDeployment(broadcast.NewDeploymentBroadcaster(ctx), gatewayName)
	d.deployments.Store(nsName, deployment)

	return deployment
}

// StoreWithBroadcaster creates a new Deployment with the supplied broadcaster and stores it.
// Used in unit tests to provide a mock broadcaster.
func (d *DeploymentStore) StoreWithBroadcaster(
	nsName types.NamespacedName,
	broadcaster broadcast.Broadcaster,
	gatewayName string,
) *Deployment {
	deployment := newDeployment(broadcaster, gatewayName)
	d.deployments.Store(nsName, deployment)

	return deployment
}

// Remove the deployment from the store.
func (d *DeploymentStore) Remove(nsName types.NamespacedName) {
	d.deployments.Delete(nsName)
}

